class Solution {
public:
    int minSwapsCouples(vector<int>& row) {
        int n = row.size() / 2;
        vector<int> parent(n);
        vector<int> size(n, 1);
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
        }
        function<int(int)> find = [&](int x) {
            while (x != parent[x]) {
                parent[x] = parent[parent[x]];
                x = parent[x];
            }
            return x;
        };
        for (int i = 0; i < row.size(); i += 2) {
            int a = row[i];
            int b = row[i + 1];
            int x = a / 2;
            int y = b / 2;
            if (x != y) {
                int rootX = find(x);
                int rootY = find(y);
                if (rootX != rootY) {
                    parent[rootY] = rootX;
                    size[rootX] += size[rootY];
                }
            }
        }
        unordered_set<int> roots;
        int swaps = 0;
        for (int i = 0; i < n; ++i) {
            int root = find(i);
            if (roots.find(root) == roots.end()) {
                roots.insert(root);
                swaps += (size[root] - 1);
            }
        }
        return swaps;
    }
};

